    protected override async Task OnPlay(PlayerChoiceContext choiceContext, CardPlay cardPlay)
    {
        var detonations = await BombPower.DetonateAll(choiceContext, CombatState!.HittableEnemies.ToList());
        for (var i = 0; i < detonations; i++)
